/* CAN bus message frame definition and transmit API */
#ifndef CAN_DRV_H
#define CAN_DRV_H

#include <stdint.h>

/* CAN FD support: max DLC increased from 8 to 64 */
#define CAN_MAX_DLC  64

typedef struct {
    uint32_t id;            /* CAN message ID */
    uint8_t  dlc;           /* Data Length Code (0-15 for CAN FD) */
    uint8_t  data[CAN_MAX_DLC]; /* LAYOUT BREAK: array size changed */
    uint8_t  is_extended;   /* 1 = 29-bit ID, 0 = 11-bit */
    uint8_t  is_fd;         /* NEW: 1 = CAN FD frame */
    uint8_t  brs;           /* NEW: bit rate switch flag */
} can_frame_t;

int can_init(uint32_t bitrate_bps);
int can_transmit(const can_frame_t *frame);
int can_receive(can_frame_t *frame, uint32_t timeout_ms);
void can_deinit(void);

#endif

